Global.initLazyLoad=()=>{const t=document.querySelectorAll("img");const e=new IntersectionObserver((t,r)=>{t.forEach(t=>{if(t.isIntersecting){const e=t.target;t=e.getAttribute("data-src");e.src=t,e.removeAttribute("lazyload"),r.unobserve(e)}})},{rootMargin:"0px",threshold:.1});t.forEach(t=>{t.hasAttribute("lazyload")&&e.observe(t)})};